// src/pages/LandingPage.js
import React, { useState } from "react";
import {
  loginUser,
  registerUser,
  loginWithGoogle,
  resetPassword,
} from "../utils/firebase";
import "./LandingPage.css";

const LOGO_PATH = "/assets/images/clario-logo.png";

export default function LandingPage({ navigate }) {
  const [mode, setMode] = useState("login");
  const [loading, setLoading] = useState(false);
  const [googleLoading, setGoogleLoading] = useState(false);
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  const [loginForm, setLoginForm] = useState({
    email: "",
    password: "",
    remember: false,
  });

  const [registerForm, setRegisterForm] = useState({
    name: "",
    email: "",
    password: "",
    confirmPassword: "",
  });

  const handleLoginChange = (e) => {
    const { name, value, type, checked } = e.target;

    setLoginForm((prev) => ({
      ...prev,
      [name]: type === "checkbox" ? checked : value,
    }));
  };

  const handleRegisterChange = (e) => {
    const { name, value } = e.target;

    setRegisterForm((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const switchMode = (nextMode) => {
    setError("");
    setMessage("");
    setMode(nextMode);
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");
    setMessage("");
    setLoading(true);

    try {
      await loginUser(loginForm.email, loginForm.password, loginForm.remember);
      navigate("dashboard");
    } catch (err) {
      setError(err.message || "Login failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    setError("");
    setMessage("");

    if (registerForm.password !== registerForm.confirmPassword) {
      setError("Passwords do not match.");
      return;
    }

    if (registerForm.password.length < 8) {
      setError("Password must be at least 8 characters.");
      return;
    }

    setLoading(true);

    try {
      await registerUser(
        registerForm.name,
        registerForm.email,
        registerForm.password
      );
      navigate("dashboard");
    } catch (err) {
      setError(err.message || "Account creation failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleForgotPassword = async () => {
    setError("");
    setMessage("");

    try {
      await resetPassword(loginForm.email);
      setMessage("Password reset email sent. Please check your inbox.");
    } catch (err) {
      setError(err.message || "Unable to send password reset email.");
    }
  };

  const handleGoogleLogin = async () => {
    setError("");
    setMessage("");
    setGoogleLoading(true);

    try {
      await loginWithGoogle(loginForm.remember);
      navigate("dashboard");
    } catch (err) {
      setError(err.message || "Google login failed. Please try again.");
    } finally {
      setGoogleLoading(false);
    }
  };

  const isLogin = mode === "login";

  return (
    <div className="lp-page">
      <div className={`lp-shell ${isLogin ? "is-login" : "is-register"}`}>
        <section className="lp-left-panel">
          <img className="lp-logo-top" src={LOGO_PATH} alt="CLARIO logo" />

          <div className="lp-left-content">
            {isLogin ? (
              <>
                <h1>Welcome back! 👋</h1>
                <p>Log in to continue your journey to confident communication.</p>

                <div className="lp-mic-art">
                  <div className="lp-bars left">
                    <span />
                    <span />
                    <span />
                    <span />
                  </div>

                  <div className="lp-mic">
                    <div className="lp-mic-head" />
                    <div className="lp-mic-stem" />
                    <div className="lp-mic-base" />
                  </div>

                  <div className="lp-bars right">
                    <span />
                    <span />
                    <span />
                    <span />
                  </div>
                </div>
              </>
            ) : (
              <>
                <h1>Create your account</h1>
                <p>Start your journey to confident communication.</p>

                <div className="lp-chat-art">
                  <div className="lp-chat-bubble">
                    <span />
                    <span />
                    <span />
                  </div>

                  <div className="lp-sound">
                    <span />
                    <span />
                    <span />
                    <span />
                    <span />
                  </div>
                </div>
              </>
            )}
          </div>

          <p className="lp-copyright">© 2026 CLARIO. All rights reserved.</p>

          <div className="lp-wave-bg">
            <svg viewBox="0 0 500 160" preserveAspectRatio="none">
              <path
                d="M0 85 C80 35 145 140 235 92 C330 38 415 50 500 90 L500 160 L0 160 Z"
                fill="rgba(124,108,252,0.13)"
              />
              <path
                d="M0 120 C90 72 155 150 245 116 C350 76 425 86 500 120 L500 160 L0 160 Z"
                fill="rgba(124,108,252,0.09)"
              />
            </svg>
          </div>
        </section>

        <section className="lp-right-panel">
          <div className="lp-dots" />

          <div className="lp-card">
            <div className="lp-form-transition" key={mode}>
              {isLogin ? (
                <>
                  <div className="lp-card-header">
                    <h2>Log in to your account</h2>
                    <p>Enter your credentials to access your dashboard.</p>
                  </div>

                  <form className="lp-form" onSubmit={handleLogin}>
                    <label className="lp-field">
                      <span>Email address</span>
                      <div className="lp-input-wrap">
                        <span className="lp-input-icon">✉</span>
                        <input
                          type="email"
                          name="email"
                          value={loginForm.email}
                          onChange={handleLoginChange}
                          placeholder="s.sanchez.rolchvincent@cmu.edu.ph"
                          required
                        />
                      </div>
                    </label>

                    <label className="lp-field">
                      <span>Password</span>
                      <div className="lp-input-wrap">
                        <span className="lp-input-icon">🔒</span>
                        <input
                          type="password"
                          name="password"
                          value={loginForm.password}
                          onChange={handleLoginChange}
                          placeholder="••••••••••"
                          required
                        />
                      </div>
                    </label>

                    <div className="lp-form-row">
                      <label className="lp-checkbox">
                        <input
                          type="checkbox"
                          name="remember"
                          checked={loginForm.remember}
                          onChange={handleLoginChange}
                        />
                        <span>Remember me</span>
                      </label>

                      <button
                        type="button"
                        className="lp-text-btn"
                        onClick={handleForgotPassword}
                      >
                        Forgot password?
                      </button>
                    </div>

                    {error && <p className="lp-error">{error}</p>}
                    {message && <p className="lp-success">{message}</p>}

                    <button
                      type="submit"
                      className="lp-submit-btn"
                      disabled={loading || googleLoading}
                    >
                      {loading ? "Logging in..." : "Log In"}
                      <span>→</span>
                    </button>

                    <div className="lp-divider">
                      <span />
                      <p>or continue with</p>
                      <span />
                    </div>

                    <button
                      type="button"
                      className="lp-social-btn lp-google-btn"
                      onClick={handleGoogleLogin}
                      disabled={loading || googleLoading}
                    >
                      <span className="lp-google">G</span>
                      {googleLoading ? "Connecting..." : "Google"}
                    </button>

                    <p className="lp-switch-text">
                      Don’t have an account?{" "}
                      <button type="button" onClick={() => switchMode("register")}>
                        Register here
                      </button>
                    </p>
                  </form>
                </>
              ) : (
                <>
                  <div className="lp-card-header">
                    <h2>Create your account</h2>
                    <p>Fill in your details to get started.</p>
                  </div>

                  <form className="lp-form" onSubmit={handleRegister}>
                    <div className="lp-register-grid">
                      <label className="lp-field">
                        <span>Full name</span>
                        <div className="lp-input-wrap">
                          <span className="lp-input-icon">👤</span>
                          <input
                            type="text"
                            name="name"
                            value={registerForm.name}
                            onChange={handleRegisterChange}
                            placeholder="e.g. Maki Aury Cliz"
                            required
                          />
                        </div>
                      </label>

                      <label className="lp-field">
                        <span>Email address</span>
                        <div className="lp-input-wrap">
                          <span className="lp-input-icon">✉</span>
                          <input
                            type="email"
                            name="email"
                            value={registerForm.email}
                            onChange={handleRegisterChange}
                            placeholder="username@cmu.edu.ph"
                            required
                          />
                        </div>
                      </label>

                      <label className="lp-field">
                        <span>Password</span>
                        <div className="lp-input-wrap">
                          <span className="lp-input-icon">🔒</span>
                          <input
                            type="password"
                            name="password"
                            value={registerForm.password}
                            onChange={handleRegisterChange}
                            placeholder="••••••••••"
                            required
                          />
                        </div>
                      </label>

                      <label className="lp-field">
                        <span>Confirm password</span>
                        <div className="lp-input-wrap">
                          <span className="lp-input-icon">🔒</span>
                          <input
                            type="password"
                            name="confirmPassword"
                            value={registerForm.confirmPassword}
                            onChange={handleRegisterChange}
                            placeholder="••••••••••"
                            required
                          />
                        </div>
                      </label>
                    </div>

                    {error && <p className="lp-error">{error}</p>}
                    {message && <p className="lp-success">{message}</p>}

                    <button type="submit" className="lp-submit-btn" disabled={loading}>
                      {loading ? "Creating account..." : "Create Account"}
                      <span>→</span>
                    </button>

                    <p className="lp-switch-text">
                      Already have an account?{" "}
                      <button type="button" onClick={() => switchMode("login")}>
                        Log in here
                      </button>
                    </p>
                  </form>
                </>
              )}
            </div>
          </div>
        </section>
      </div>
    </div>
  );
}
